```go
import "container/heap"

type Edge struct{ to, cost int }
type Graph [][]Edge

// item in the priority queue
type Item struct{ node, dist int }
type PQ []Item

func (pq PQ) Len() int            { return len(pq) }
func (pq PQ) Less(i, j int) bool  { return pq[i].dist < pq[j].dist }
func (pq PQ) Swap(i, j int)       { pq[i], pq[j] = pq[j], pq[i] }
func (pq *PQ) Push(x any)         { *pq = append(*pq, x.(Item)) }
func (pq *PQ) Pop() any {
	old := *pq; n := len(old)
	v := old[n-1]; *pq = old[:n-1]
	return v
}

func Dijkstra(g Graph, src int) []int {
	const inf = 1<<62 - 1
	dist := make([]int, len(g))
	for i := range dist { dist[i] = inf }
	dist[src] = 0

	pq := &PQ{{src, 0}}
	heap.Init(pq)

	for pq.Len() > 0 {
		cur := heap.Pop(pq).(Item)
		if cur.dist > dist[cur.node] {
			continue // stale entry
		}
		for _, e := range g[cur.node] {
			if nd := cur.dist + e.cost; nd < dist[e.to] {
				dist[e.to] = nd
				heap.Push(pq, Item{e.to, nd})
			}
		}
	}
	return dist
}
```

**Data structure rationale:**
- **Min-heap (binary heap):** extract-min is O(log n), push is O(log n). Overall: O((V+E) log V).
- **Adjacency list:** O(V+E) space vs O(V²) for a matrix; efficient for sparse graphs.
- **Lazy deletion:** instead of decreasing key (complex), push a new Item and skip stale entries (`cur.dist > dist[cur.node]`). Simple to implement in Go with `container/heap`.
- **Alternative — Fibonacci heap:** O(E + V log V) theoretical complexity, but impractical due to high constant factors; rarely used outside academia.

